const searchCampusProfiles = `-- name: SearchCampusProfiles :many
SELECT cp.id, cp.user_id, cp.bio, cp.interests, cp.skills, cp.availability_status, cp.last_active_at, cp.connection_count, cp.post_count, cp.created_at, cp.updated_at, u.full_name, u.avatar_url, u.role
FROM campus_profiles cp
JOIN users u ON u.id = cp.user_id
WHERE u.is_active = true AND u.is_approved = true
  AND ($1 = '' OR cp.skills @> to_jsonb($1::text) OR cp.interests @> to_jsonb($1::text) OR u.full_name ILIKE '%' || $1 || '%')
ORDER BY cp.last_active_at DESC
LIMIT $2 OFFSET $3
`

type SearchCampusProfilesParams struct {
	Column1 interface{} `json:"column_1"`
	Limit   int32       `json:"limit"`
	Offset  int32       `json:"offset"`
}

type SearchCampusProfilesRow struct {
	ID                 uuid.UUID          `json:"id"`
	UserID             uuid.UUID          `json:"user_id"`
	Bio                *string            `json:"bio"`
	Interests          []byte             `json:"interests"`
	Skills             []byte             `json:"skills"`
	AvailabilityStatus string             `json:"availability_status"`
	LastActiveAt       pgtype.Timestamptz `json:"last_active_at"`
	ConnectionCount    int32              `json:"connection_count"`
	PostCount          int32              `json:"post_count"`
	CreatedAt          pgtype.Timestamptz `json:"created_at"`
	UpdatedAt          pgtype.Timestamptz `json:"updated_at"`
	FullName           string             `json:"full_name"`
	AvatarUrl          *string            `json:"avatar_url"`
	Role               UserRole           `json:"role"`
}

func (q *Queries) SearchCampusProfiles(ctx context.Context, arg SearchCampusProfilesParams) ([]SearchCampusProfilesRow, error) {
	rows, err := q.db.Query(ctx, searchCampusProfiles, arg.Column1, arg.Limit, arg.Offset)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []SearchCampusProfilesRow{}
	for rows.Next() {
		var i SearchCampusProfilesRow
		if err := rows.Scan(
			&i.ID,
			&i.UserID,
			&i.Bio,
			&i.Interests,
			&i.Skills,
			&i.AvailabilityStatus,
			&i.LastActiveAt,
			&i.ConnectionCount,
			&i.PostCount,
			&i.CreatedAt,
			&i.UpdatedAt,
			&i.FullName,
			&i.AvatarUrl,
			&i.Role,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

const searchPeople = `-- name: SearchPeople :many
SELECT u.id, u.full_name, u.avatar_url, u.role, u.email,
       s.matric_number, s.level,
       COALESCE(cp.bio, '') AS bio,
       COALESCE(cp.skills, '[]') AS skills,
       COALESCE(cp.interests, '[]') AS interests,
       COALESCE(cp.availability_status, 'offline') AS availability_status
FROM users u
LEFT JOIN students s ON s.user_id = u.id
LEFT JOIN campus_profiles cp ON cp.user_id = u.id
WHERE u.is_active = true AND u.is_approved = true
  AND (u.full_name ILIKE '%' || $1 || '%' OR s.matric_number ILIKE '%' || $1 || '%')
ORDER BY u.full_name
LIMIT $2 OFFSET $3
`

