const upsertCampusProfile = `-- name: UpsertCampusProfile :one

INSERT INTO campus_profiles (user_id, bio, interests, skills, availability_status)
VALUES ($1, $2, $3, $4, $5)
ON CONFLICT (user_id) DO UPDATE
SET bio = EXCLUDED.bio, interests = EXCLUDED.interests, skills = EXCLUDED.skills,
    availability_status = EXCLUDED.availability_status, updated_at = NOW()
RETURNING id, user_id, bio, interests, skills, availability_status, last_active_at, connection_count, post_count, created_at, updated_at
`

type UpsertCampusProfileParams struct {
	UserID             uuid.UUID `json:"user_id"`
	Bio                *string   `json:"bio"`
	Interests          []byte    `json:"interests"`
	Skills             []byte    `json:"skills"`
	AvailabilityStatus string    `json:"availability_status"`
}

// ==================== CAMPUS PROFILES ====================
func (q *Queries) UpsertCampusProfile(ctx context.Context, arg UpsertCampusProfileParams) (CampusProfile, error) {
	row := q.db.QueryRow(ctx, upsertCampusProfile,
		arg.UserID,
		arg.Bio,
		arg.Interests,
		arg.Skills,
		arg.AvailabilityStatus,
	)
	var i CampusProfile
	err := row.Scan(
		&i.ID,
		&i.UserID,
		&i.Bio,
		&i.Interests,
		&i.Skills,
		&i.AvailabilityStatus,
		&i.LastActiveAt,
		&i.ConnectionCount,
		&i.PostCount,
		&i.CreatedAt,
		&i.UpdatedAt,
	)
	return i, err
}
